// NewQueryInsightsPayload builds a skillEfficacy service queryInsights
// endpoint payload.
func NewQueryInsightsPayload(skillIds []string, from *string, to *string, includeVersions *bool, includeScoredSessions *bool, sessionToken *string, projectSlugInput *string) *skillefficacy.QueryInsightsPayload {
	v := &skillefficacy.QueryInsightsPayload{}
	v.SkillIds = skillIds
	v.From = from
	v.To = to
	v.IncludeVersions = includeVersions
	v.IncludeScoredSessions = includeScoredSessions
	v.SessionToken = sessionToken
	v.ProjectSlugInput = projectSlugInput

	return v
}

// ValidateUpsertSettingsRequestBody runs the validations defined on
// UpsertSettingsRequestBody
func ValidateUpsertSettingsRequestBody(body *UpsertSettingsRequestBody) (err error) {
	if body.Enabled == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("enabled", "body"))
	}
	if body.DailyCap == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("daily_cap", "body"))
	}
	if body.DailyCap != nil {
		if *body.DailyCap < 0 {
			err = goa.MergeErrors(err, goa.InvalidRangeError("body.daily_cap", *body.DailyCap, 0, true))
		}
	}
	if body.DailyCap != nil {
		if *body.DailyCap > 10000 {
			err = goa.MergeErrors(err, goa.InvalidRangeError("body.daily_cap", *body.DailyCap, 10000, false))
		}
	}
	return
}
